@using sv_24612d4f9a80452bb9b199e3a207b670.Services

<div class="channel-item @(IsActive ? "active" : "")" @onclick="HandleClick">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-desc">@TruncatedDescription</div>
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback<int> OnSelected { get; set; }

    private string TruncatedDescription =>
        Channel.Description.Length > 40
            ? Channel.Description[..37] + "..."
            : Channel.Description;

    private async Task HandleClick() => await OnSelected.InvokeAsync(Channel.Id);
}

.channel-item {
    padding: 0.6rem 0.9rem;
    cursor: pointer;
    border-radius: 6px;
    margin: 0.15rem 0.4rem;
    transition: background-color 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.12);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.2);
}

.channel-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
    color: #fff;
}

.channel-desc {
    font-size: 0.78rem;
    color: rgba(255, 255, 255, 0.6);
    margin-top: 0.15rem;
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
}

.unread-badge {
    background: #e74c3c;
    color: #fff;
    border-radius: 10px;
    padding: 0.1rem 0.45rem;
    font-size: 0.72rem;
    font-weight: 700;
    min-width: 1.1rem;
    text-align: center;
    line-height: 1.3;
}

