toolArgs.file_text:
.message-item {
    position: relative;
    padding: 0.6rem 1rem;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background: #f5f5f5;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 0.5rem;
    margin-bottom: 0.2rem;
}

.author {
    font-weight: 700;
    font-size: 0.93rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.76rem;
    color: #8e8e8e;
}

.message-content {
    font-size: 0.92rem;
    line-height: 1.45;
    color: #333;
    white-space: pre-wrap;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 0.3rem;
    margin-top: 0.35rem;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 0.2rem;
    background: #eef1f5;
    border: 1px solid #d8dde3;
    border-radius: 12px;
    padding: 0.15rem 0.5rem;
    font-size: 0.8rem;
    cursor: pointer;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #dde3ea;
}

.thread-link {
    background: none;
    border: none;
    color: #4a76a8;
    font-size: 0.82rem;
    font-weight: 600;
    cursor: pointer;
    padding: 0.2rem 0;
    margin-top: 0.25rem;
}

.thread-link:hover {
    text-decoration: underline;
}

.hover-actions {
    position: absolute;
    top: 0.3rem;
    right: 0.5rem;
    display: flex;
    gap: 0.15rem;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.15rem;
