arguments.file_text:
@using sv_24612d4f9a80452bb9b199e3a207b670.Services

<div class="channel-sidebar">
    <div class="sidebar-header">
        <h5>Channels</h5>
    </div>
    <div class="channel-list">
        @foreach (var channel in Channels)
        {
            <ChannelItem Channel="channel"
                         IsActive="channel.Id == SelectedChannelId"
                         OnSelected="OnChannelSelected" />
        }
    </div>
</div>

@code {
    [Parameter] public List<Channel> Channels { get; set; } = [];
    [Parameter] public int SelectedChannelId { get; set; }
    [Parameter] public EventCallback<int> OnChannelSelected { get; set; }
}

.channel-sidebar {
    display: flex;
    flex-direction: column;
    background: #2c3e50;
    color: #fff;
    height: 100%;
    overflow: hidden;
}

.sidebar-header {
    padding: 1rem;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
}

.sidebar-header h5 {
    margin: 0;
    font-size: 1rem;
    font-weight: 700;
    text-transform: uppercase;
    letter-spacing: 0.05em;
    color: rgba(255, 255, 255, 0.8);
}

.channel-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.4rem 0;
}

@using sv_24612d4f9a80452bb9b199e3a207b670.Services

<div class="message-list" @onscroll="HandleScroll">
    @if (IsLoadingMore)
    {
        <div class="load-more-indicator">Loading older messages...</div>
    }
    else if (HasMoreMessages)
    {
        <div class="scroll-sentinel">
            <button class="btn btn-sm btn-outline-secondary load-more-btn" @onclick="OnLoadMore">
                Load older messages
            </button>
        </div>
    }

    @foreach (var message in Messages)
    {
        <MessageItem Message="message"
                     ReplyCount="GetReplyCount(message.Id)"
                     OnOpenThread="OnOpenThread"
                     OnReact="OnReact" />
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; } = true;
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }

    private int GetReplyCount(int messageId) =>
        ReplyCounts.TryGetValue(messageId, out var count) ? count : 0;

    private async Task HandleScroll(EventArgs e)
    {
        // Scroll-to-top triggers load more via JS interop would be ideal,
        // but the "Load older messages" button provides the same UX reliably.
    }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 0.5rem 0;
    display: flex;
    flex-direction: column;
}

.scroll-sentinel {
    display: flex;
    justify-content: center;
    padding: 0.5rem;
}

.load-more-btn {
    font-size: 0.8rem;
}

.load-more-indicator {
    text-align: center;
    padding: 0.75rem;
    color: #888;
    font-size: 0.85rem;
}

@using sv_24612d4f9a80452bb9b199e3a207b670.Services

<div class="message-area">
    <div class="area-header">
        <h4># @ChannelName</h4>
        <span class="area-desc">@ChannelDescription</span>
    </div>

    <MessageList Messages="Messages"
                 ReplyCounts="ReplyCounts"
                 IsLoadingMore="IsLoadingMore"
                 HasMoreMessages="HasMoreMessages"
                 OnLoadMore="OnLoadMore"
                 OnOpenThread="OnOpenThread"
                 OnReact="OnReact" />

    <MessageInput Placeholder="@($"Message #{ChannelName}")"
                  ButtonText="Send"
                  OnSend="OnSendMessage" />
</div>

@code {
    [Parameter] public string ChannelName { get; set; } = "";
    [Parameter] public string ChannelDescription { get; set; } = "";
    [Parameter] public List<Message> Messages { get; set; } = [];
    [Parameter] public Dictionary<int, int> ReplyCounts { get; set; } = [];
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public bool HasMoreMessages { get; set; } = true;
    [Parameter] public EventCallback OnLoadMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
}

.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 0.75rem 1rem;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h4 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
    color: #1a1a1a;
}

.area-desc {
    font-size: 0.82rem;
    color: #777;
}

@using sv_24612d4f9a80452bb9b199e3a207b670.Services

<div class="thread-panel">
    <div class="thread-header">
        <h5>Thread</h5>
        <button class="close-btn" @onclick="OnClose" title="Close thread">&times;</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@Replies.Count @(Replies.Count == 1 ? "reply" : "replies")</span>
        </div>

        <div class="thread-replies">
            @foreach (var reply in Replies)
            {
                <MessageItem Message="reply"
                             ReplyCount="0"
                             OnOpenThread="OnOpenThread"
                             OnReact="OnReact" />
            }
        </div>

        <MessageInput Placeholder="Reply..."
                      ButtonText="Reply"
                      OnSend="OnSendReply" />
    }
</div>

