arguments.file_text:
@page "/chat"
@rendermode InteractiveServer
@using sv_24612d4f9a80452bb9b199e3a207b670.Services
@using sv_24612d4f9a80452bb9b199e3a207b670.Components.Chat
@inject IChatService ChatService

<PageTitle>Chat</PageTitle>

<div class="chat-layout">
    <div class="chat-sidebar">
        <ChannelSidebar Channels="_channels"
                        SelectedChannelId="_selectedChannelId"
                        OnChannelSelected="SelectChannel" />
    </div>

    <div class="chat-main @(_threadRootMessage is null ? "full-width" : "")">
        @if (_selectedChannel is not null)
        {
            <MessageArea ChannelName="@_selectedChannel.Name"
                         ChannelDescription="@_selectedChannel.Description"
                         Messages="_messages"
                         ReplyCounts="_replyCounts"
                         IsLoadingMore="_isLoadingMore"
                         HasMoreMessages="_hasMoreMessages"
                         OnLoadMore="LoadMoreMessages"
                         OnOpenThread="OpenThread"
                         OnReact="AddReaction"
                         OnSendMessage="SendMessage" />
        }
        else
        {
            <div class="no-channel-selected">
                <p>Select a channel to start chatting</p>
            </div>
        }
    </div>

    @if (_threadRootMessage is not null)
    {
        <div class="chat-thread">
            <ThreadPanel RootMessage="_threadRootMessage"
                         Replies="_threadReplies"
                         OnClose="CloseThread"
                         OnSendReply="SendThreadReply"
                         OnOpenThread="OpenThread"
                         OnReact="AddReaction" />
        </div>
    }
</div>

@code {
    private const int PageSize = 30;

    private List<Channel> _channels = [];
    private List<Message> _messages = [];
    private List<Message> _threadReplies = [];
    private Dictionary<int, int> _replyCounts = [];
    private Channel? _selectedChannel;
    private int _selectedChannelId;
    private Message? _threadRootMessage;
    private int _skip;
    private bool _isLoadingMore;
    private bool _hasMoreMessages = true;

    protected override async Task OnInitializedAsync()
    {
        _channels = await ChatService.GetChannelsAsync();
        if (_channels.Count > 0)
        {
            await SelectChannel(_channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        _selectedChannelId = channelId;
        _selectedChannel = _channels.FirstOrDefault(c => c.Id == channelId);
        _skip = 0;
        _hasMoreMessages = true;
        _messages = [];
        _threadRootMessage = null;
        _threadReplies = [];

        var messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        _messages = messages;
        _skip = messages.Count;
        _hasMoreMessages = messages.Count >= PageSize;

        ComputeReplyCounts();
        await ChatService.MarkChannelReadAsync(channelId);
    }

    private async Task LoadMoreMessages()
    {
        if (_isLoadingMore || !_hasMoreMessages || _selectedChannel is null) return;

        _isLoadingMore = true;
        var older = await ChatService.GetMessagesAsync(_selectedChannel.Id, _skip, PageSize);
        _messages.InsertRange(0, older);
        _skip += older.Count;
        _hasMoreMessages = older.Count >= PageSize;
        _isLoadingMore = false;

        ComputeReplyCounts();
    }

    private async Task SendMessage(string content)
    {
        if (_selectedChannel is null) return;
        var msg = await ChatService.SendMessageAsync(_selectedChannel.Id, content, null);
        _messages.Add(msg);
    }

    private async Task OpenThread(int rootMessageId)
    {
        _threadRootMessage = _messages.FirstOrDefault(m => m.Id == rootMessageId);
        if (_threadRootMessage is null) return;

        _threadReplies = await ChatService.GetThreadAsync(rootMessageId);
    }

    private void CloseThread()
    {
        _threadRootMessage = null;
        _threadReplies = [];
    }

    private async Task SendThreadReply(string content)
    {
        if (_threadRootMessage is null || _selectedChannel is null) return;

        var reply = await ChatService.SendMessageAsync(
            _selectedChannel.Id, content, _threadRootMessage.Id);
        _threadReplies.Add(reply);

        // Update reply count
        _replyCounts[_threadRootMessage.Id] =
            _replyCounts.GetValueOrDefault(_threadRootMessage.Id) + 1;
    }

    private async Task AddReaction((int MessageId, string Emoji) args)
    {
        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);

        UpdateReactionLocally(_messages, args.MessageId, args.Emoji);
        UpdateReactionLocally(_threadReplies, args.MessageId, args.Emoji);
    }

    private static void UpdateReactionLocally(List<Message> messages, int messageId, string emoji)
    {
        var msg = messages.FirstOrDefault(m => m.Id == messageId);
        if (msg is null) return;

        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == emoji);
        if (existing is not null)
        {
            if (!existing.Users.Contains("You"))
                existing.Users.Add("You");
        }
        else
        {
            msg.Reactions.Add(new Reaction(emoji, ["You"]));
        }
    }

    private void ComputeReplyCounts()
    {
        _replyCounts = [];
        foreach (var msg in _messages.Where(m => m.ReplyToId is not null))
        {
            var rootId = msg.ReplyToId!.Value;
            _replyCounts[rootId] = _replyCounts.GetValueOrDefault(rootId) + 1;
        }
    }
}

.chat-layout {
    display: flex;
    height: 100vh;
    overflow: hidden;
}

.chat-sidebar {
    width: 20%;
    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.chat-main.full-width {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 260px;
    max-width: 400px;
    flex-shrink: 0;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

