    min-width: 200px;
    max-width: 280px;
    flex-shrink: 0;
}

.chat-main {
    flex: 1;
    min-width: 0;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.chat-main.full-width {
    flex: 1;
}

.chat-thread {
    width: 25%;
    min-width: 260px;
    max-width: 400px;
    flex-shrink: 0;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #999;
    font-size: 1.1rem;
}

